/** A shortcut for defining Xss types. */
export type Xss<P extends keyof Properties> = Pick<Properties, P>;

/** The shared marker token for `when(marker, relationship, pseudo)`. */
export const marker: Marker = Symbol.for("truss-default-marker");

/** An entry point for build-time Css expressions. Use with `css=` props. */
export const Css = new CssBuilder<Pick<Properties, never>, "buildtime">({
  rules: {} as Pick<Properties, never>,
  enabled: true,
  selector: undefined,
  elseApplied: false,
  runtimeError: undefined,
});

/** An entry point for runtime Css expressions. Use with `useRuntimeStyle`. */
export const RuntimeCss = new CssBuilder<Pick<Properties, never>, "runtime">({
  rules: {} as Pick<Properties, never>,
  enabled: true,
  selector: undefined,
  elseApplied: false,
  runtimeError: undefined,
});

/** Hook that injects dynamic CSS at runtime. Only accepts `RuntimeCss.*.$` expressions. */
export function useRuntimeStyle(css: Record<string, RuntimeStyles | string>): void {
  _useRuntimeStyle(css as any);
}

export type Margin = "margin" | "marginTop" | "marginRight" | "marginBottom" | "marginLeft";

export type Padding = "padding" | "paddingTop" | "paddingRight" | "paddingBottom" | "paddingLeft";

export type Font = "fontSize" | "fontWeight" | "lineHeight";

export type Breakpoint = "print" | "sm" | "md" | "smOrMd" | "mdAndUp" | "mdAndDown" | "lg" | "mdOrLg";
export enum Breakpoints {
  print = "@media print",
  sm = "@media screen and (max-width: 599px)",
  md = "@media screen and (min-width: 600px) and (max-width: 1024px)",
  smOrMd = "@media screen and (max-width: 1024px)",
  mdAndUp = "@media screen and (min-width: 600px)",
  mdAndDown = "@media screen and (max-width: 1024px)",
  lg = "@media screen and (min-width: 1025px)",
  mdOrLg = "@media screen and (min-width: 600px)",
}
